import { useState } from "react";
import Sidebar from "./Sidebar";
import Topbar from "./Topbar";

export default function Projectdetails() {
  const [showForm, setShowForm] = useState(false);

  const [formData, setFormData] = useState({
    projectName: "",
    location: "",
    budget: "",
    floors: "",
    startDate: "",
    endDate: "",
    description: "",
  });

  // Get today's date (YYYY-MM-DD format)
  const today = new Date().toISOString().split("T")[0];

  const handleChange = (e) => {
    const { name, value } = e.target;

    // Budget limit (Max 5 Crore = 50,000,000)
    if (name === "budget" && value > 50000000) return;

    // Floor limit (1–30)
    if (name === "floors" && value > 30) return;

    setFormData({ ...formData, [name]: value });
  };

  const handleSubmit = () => {
    console.log(formData); // later connect to database
    alert("Project Added Successfully!");
    setShowForm(false);
  };

  return (
    <div className="flex bg-gray-100 min-h-screen">
      <Sidebar />

      <div className="flex-1 flex flex-col">
        <Topbar />

        <div className="p-8">

          {/* ================= HEADER ================= */}
          {!showForm && (
            <>
              <div className="flex justify-between items-center mb-6">
                <div>
                  <h1 className="text-3xl font-bold">Project Details</h1>
                  <p className="text-gray-500">
                    Manage all construction projects, floors and rooms
                  </p>
                </div>

                <button
                  onClick={() => setShowForm(true)}
                  className="bg-orange-500 hover:bg-orange-600 text-white px-6 py-3 rounded-xl font-medium shadow"
                >
                  + Add New Project
                </button>
              </div>

              {/* Search Bar */}
              <div className="bg-white p-4 rounded-2xl shadow mb-6">
                <input
                  type="text"
                  placeholder="Search projects by name or location..."
                  className="w-full px-5 py-3 border border-gray-300 rounded-xl focus:outline-none focus:ring-2 focus:ring-orange-400"
                />
              </div>

              {/* Empty State */}
              <div className="bg-white rounded-2xl shadow flex flex-col items-center justify-center py-24 text-gray-500">
                <div className="text-6xl mb-4">✖</div>
                <p className="text-lg">
                  No projects found. Add your first project to get started.
                </p>
              </div>
            </>
          )}

          {/* ================= FORM ================= */}
          {showForm && (
            <div className="bg-white p-8 rounded-2xl shadow">
              <h2 className="text-2xl font-semibold mb-6">
                Add New Project
              </h2>

              <div className="grid grid-cols-2 gap-6">

                {/* Project Name */}
                <div>
                  <label className="block mb-2 font-medium">
                    Project Name
                  </label>
                  <input
                    type="text"
                    name="projectName"
                    value={formData.projectName}
                    onChange={handleChange}
                    placeholder="Project Name"
                    className="w-full px-4 py-3 border rounded-xl"
                  />
                </div>

                {/* Location */}
                <div>
                  <label className="block mb-2 font-medium">
                    Location
                  </label>
                  <input
                    type="text"
                    name="location"
                    value={formData.location}
                    onChange={handleChange}
                    placeholder="Location"
                    className="w-full px-4 py-3 border rounded-xl"
                  />
                </div>

                {/* Budget */}
                <div>
                  <label className="block mb-2 font-medium">
                    Budget (₹) (Max 5 Cr)
                  </label>
                  <input
                    type="number"
                    name="budget"
                    value={formData.budget}
                    onChange={handleChange}
                    max="50000000"
                    placeholder="Max ₹5,00,00,000"
                    className="w-full px-4 py-3 border rounded-xl"
                  />
                </div>

                {/* Floors */}
                <div>
                  <label className="block mb-2 font-medium">
                    Number of Floors (1-30)
                  </label>
                  <input
                    type="number"
                    name="floors"
                    value={formData.floors}
                    onChange={handleChange}
                    min="1"
                    max="30"
                    placeholder="1 - 30"
                    className="w-full px-4 py-3 border rounded-xl"
                  />
                </div>

                {/* Start Date */}
                <div>
                  <label className="block mb-2 font-medium">
                    Start Date
                  </label>
                  <input
                    type="date"
                    name="startDate"
                    value={formData.startDate}
                    onChange={handleChange}
                    max={today}   // 🚀 cannot go future
                    className="w-full px-4 py-3 border rounded-xl"
                  />
                </div>

                {/* End Date */}
                <div>
                  <label className="block mb-2 font-medium">
                    End Date
                  </label>
                  <input
                    type="date"
                    name="endDate"
                    value={formData.endDate}
                    onChange={handleChange}
                    min={formData.startDate}  // 🚀 must be after start date
                    className="w-full px-4 py-3 border rounded-xl"
                  />
                </div>

              </div>

              {/* Description */}
              <div className="mt-6">
                <label className="block mb-2 font-medium">
                  Project Description
                </label>
                <textarea
                  name="description"
                  value={formData.description}
                  onChange={handleChange}
                  rows="4"
                  placeholder="Project Description"
                  className="w-full px-4 py-3 border rounded-xl"
                />
              </div>

              <div className="mt-6 flex gap-4">
                <button
                  onClick={handleSubmit}
                  className="bg-orange-500 text-white px-6 py-3 rounded-xl"
                >
                  Add Project
                </button>

                <button
                  onClick={() => setShowForm(false)}
                  className="bg-gray-300 px-6 py-3 rounded-xl"
                >
                  Cancel
                </button>
              </div>
            </div>
          )}

        </div>
      </div>
    </div>
  );
}
